INSERT INTO fungal_classifications (fungal_classification_id, slug, name, classification_group, habitat, health_notes, source_url, updated_at) OVERRIDING SYSTEM VALUE VALUES (1, 'ascospore', 'Ascospore', 'predominantly_outdoor', 'Outdoor, decaying vegetation.', 'Low health relevance indoors; outdoor baseline only.', NULL, '2026-01-15T00:00:00Z');
INSERT INTO fungal_classifications (fungal_classification_id, slug, name, classification_group, habitat, health_notes, source_url, updated_at) OVERRIDING SYSTEM VALUE VALUES (2, 'basidiospore', 'Basidiospore', 'predominantly_outdoor', 'Outdoor, wood-rotting fungi.', 'Outdoor baseline.', NULL, '2026-01-15T00:00:00Z');
INSERT INTO fungal_classifications (fungal_classification_id, slug, name, classification_group, habitat, health_notes, source_url, updated_at) OVERRIDING SYSTEM VALUE VALUES (3, 'stachybotrys', 'Stachybotrys', 'predominantly_indoor_water_related', 'Wet cellulose — saturated drywall, ceiling tiles.', 'Often described as the ''black mould''. Indoor presence indicates active wetting.', NULL, '2026-01-15T00:00:00Z');
INSERT INTO fungal_classifications (fungal_classification_id, slug, name, classification_group, habitat, health_notes, source_url, updated_at) OVERRIDING SYSTEM VALUE VALUES (4, 'aspergillus-penicillium', 'Aspergillus / Penicillium', 'indoor_outdoor', 'Both indoor and outdoor; common indoor amplifier in damp homes.', 'Allergenic; some species mycotoxic. Elevated indoor counts vs outdoor warrant action.', NULL, '2026-01-15T00:00:00Z');
INSERT INTO fungal_classifications (fungal_classification_id, slug, name, classification_group, habitat, health_notes, source_url, updated_at) OVERRIDING SYSTEM VALUE VALUES (5, 'cladosporium', 'Cladosporium', 'indoor_outdoor', 'Indoor and outdoor; very common allergen.', 'Allergenic — elevated indoor levels can drive respiratory symptoms.', NULL, '2026-01-15T00:00:00Z');
INSERT INTO fungal_classifications (fungal_classification_id, slug, name, classification_group, habitat, health_notes, source_url, updated_at) OVERRIDING SYSTEM VALUE VALUES (6, 'alternaria', 'Alternaria', 'predominantly_outdoor', 'Outdoor, on leaves and soil.', 'Common asthma trigger; elevated indoor counts unusual.', NULL, '2026-01-15T00:00:00Z');
INSERT INTO fungal_classifications (fungal_classification_id, slug, name, classification_group, habitat, health_notes, source_url, updated_at) OVERRIDING SYSTEM VALUE VALUES (7, 'bipolaris', 'Bipolaris / Drechslera', 'predominantly_outdoor', 'Outdoor, grass and grain pathogens.', 'Outdoor baseline.', NULL, '2026-01-15T00:00:00Z');
INSERT INTO fungal_classifications (fungal_classification_id, slug, name, classification_group, habitat, health_notes, source_url, updated_at) OVERRIDING SYSTEM VALUE VALUES (8, 'chaetomium', 'Chaetomium', 'predominantly_indoor_water_related', 'Cellulose substrates — wet plasterboard, books.', 'Indoor presence indicates a chronic moisture source.', NULL, '2026-01-15T00:00:00Z');
INSERT INTO fungal_classifications (fungal_classification_id, slug, name, classification_group, habitat, health_notes, source_url, updated_at) OVERRIDING SYSTEM VALUE VALUES (9, 'curvularia', 'Curvularia', 'predominantly_outdoor', 'Outdoor, tropical grasses.', 'Outdoor baseline.', NULL, '2026-01-15T00:00:00Z');
INSERT INTO fungal_classifications (fungal_classification_id, slug, name, classification_group, habitat, health_notes, source_url, updated_at) OVERRIDING SYSTEM VALUE VALUES (10, 'epicoccum', 'Epicoccum', 'predominantly_outdoor', 'Outdoor, plant pathogen + decay.', 'Outdoor baseline.', NULL, '2026-01-15T00:00:00Z');
INSERT INTO fungal_classifications (fungal_classification_id, slug, name, classification_group, habitat, health_notes, source_url, updated_at) OVERRIDING SYSTEM VALUE VALUES (11, 'fusarium', 'Fusarium', 'predominantly_indoor_water_related', 'Wet substrates — sub-floor, leaking drains.', 'Some species produce mycotoxins; indoor presence warrants source investigation.', NULL, '2026-01-15T00:00:00Z');
INSERT INTO fungal_classifications (fungal_classification_id, slug, name, classification_group, habitat, health_notes, source_url, updated_at) OVERRIDING SYSTEM VALUE VALUES (12, 'mucor-rhizopus', 'Mucor / Rhizopus', 'indoor_outdoor', 'Soil + decaying produce; opportunistic indoor.', 'Allergenic; elevated indoor counts indicate active substrate.', NULL, '2026-01-15T00:00:00Z');
INSERT INTO fungal_classifications (fungal_classification_id, slug, name, classification_group, habitat, health_notes, source_url, updated_at) OVERRIDING SYSTEM VALUE VALUES (13, 'nigrospora', 'Nigrospora', 'predominantly_outdoor', 'Outdoor, on dead plant matter.', 'Outdoor baseline.', NULL, '2026-01-15T00:00:00Z');
INSERT INTO fungal_classifications (fungal_classification_id, slug, name, classification_group, habitat, health_notes, source_url, updated_at) OVERRIDING SYSTEM VALUE VALUES (14, 'pithomyces', 'Pithomyces', 'predominantly_outdoor', 'Outdoor, pasture grass.', 'Outdoor baseline.', NULL, '2026-01-15T00:00:00Z');
INSERT INTO fungal_classifications (fungal_classification_id, slug, name, classification_group, habitat, health_notes, source_url, updated_at) OVERRIDING SYSTEM VALUE VALUES (15, 'rust-uredinales', 'Rust (Uredinales)', 'predominantly_outdoor', 'Outdoor, obligate plant parasite.', 'Outdoor baseline.', NULL, '2026-01-15T00:00:00Z');
INSERT INTO fungal_classifications (fungal_classification_id, slug, name, classification_group, habitat, health_notes, source_url, updated_at) OVERRIDING SYSTEM VALUE VALUES (16, 'smut-periconia', 'Smut / Periconia', 'predominantly_outdoor', 'Outdoor, grass pathogens.', 'Outdoor baseline.', NULL, '2026-01-15T00:00:00Z');
INSERT INTO fungal_classifications (fungal_classification_id, slug, name, classification_group, habitat, health_notes, source_url, updated_at) OVERRIDING SYSTEM VALUE VALUES (17, 'torula', 'Torula', 'indoor_outdoor', 'Outdoor + indoor; weak amplifier.', 'Mild allergen; rarely the lead species.', NULL, '2026-01-15T00:00:00Z');
INSERT INTO fungal_classifications (fungal_classification_id, slug, name, classification_group, habitat, health_notes, source_url, updated_at) OVERRIDING SYSTEM VALUE VALUES (18, 'trichoderma', 'Trichoderma', 'predominantly_indoor_water_related', 'Wet cellulose + soil; common after flood events.', 'Indoor presence suggests a wetting event in the last 6–12 months.', NULL, '2026-01-15T00:00:00Z');
INSERT INTO fungal_classifications (fungal_classification_id, slug, name, classification_group, habitat, health_notes, source_url, updated_at) OVERRIDING SYSTEM VALUE VALUES (19, 'ulocladium', 'Ulocladium', 'predominantly_indoor_water_related', 'Wet substrates — saturated drywall, carpet.', 'Indoor amplifier; often co-located with Stachybotrys.', NULL, '2026-01-15T00:00:00Z');
INSERT INTO fungal_classifications (fungal_classification_id, slug, name, classification_group, habitat, health_notes, source_url, updated_at) OVERRIDING SYSTEM VALUE VALUES (20, 'myxomycetes', 'Myxomycetes', 'predominantly_outdoor', 'Outdoor, rotting wood.', 'Outdoor baseline.', NULL, '2026-01-15T00:00:00Z');
